        for j in range(N):
            pos[grid[i][j]] = (i, j)

    def get_neighbors(i, j):
        neighbors = []
        for di, dj in [(-1,0),(1,0),(0,-1),(0,1)]:
            ni, nj = i+di, j+dj
            if 0 <= ni < N and 0 <= nj < N:
                neighbors.append((ni, nj))
        return neighbors

    # BFS/DFS to find minimum path of length k
    # Use dynamic programming approach
    # dp[step][i][j] = minimum path list ending at (i,j) after step steps
    # But storing lists is expensive, instead we can use the fact that
    # we want lexicographically minimum path

